331:     const colors = ["#ef4444", "#f59e0b", "#3b82f6", "#10b981"]; // Critical, High Risk, Suspicious, Safe
332: 
333:     const total = data.reduce((sum, val) => sum + val, 0);
334:     if (total === 0) return;
335: 
336:     let startAngle = -Math.PI / 2;
337:     const cx = canvas.width / 2;
338:     const cy = canvas.height / 2;
339:     const outerRadius = Math.min(cx, cy) - 5;
340:     const innerRadius = outerRadius - 16;
341: 
342:     data.forEach((val, idx) => {
343:         if (val === 0) return;
344:         const sliceAngle = (val / total) * 2 * Math.PI;
345:         
346:         ctx.beginPath();
347:         ctx.arc(cx, cy, outerRadius, startAngle, startAngle + sliceAngle);
348:         ctx.arc(cx, cy, innerRadius, startAngle + sliceAngle, startAngle, true);
349:         ctx.closePath();
350:         
351:         ctx.fillStyle = colors[idx];
352:         ctx.fill();
353:         
354:         // Glass shadow effect
355:         ctx.strokeStyle = "rgba(10, 8, 22, 0.4)";
356:         ctx.lineWidth = 2;
357:         ctx.stroke();
358: 
359:         startAngle += sliceAngle;
360:     });
361: }
