    margin-bottom: 15px;
}

.login-header-section h2 {
    font-size: 1.8rem;
    margin-bottom: 5px;
}

.login-header-section p {
    color: var(--text-secondary);
    font-size: 0.9rem;
}

.login-form {
    display: flex;
    flex-direction: column;
    gap: 20px;
}

.login-form .form-group {
    display: flex;
    flex-direction: column;
    gap: 8px;
}

.login-form label {
    font-size: 0.85rem;
    font-weight: 600;
    color: var(--text-secondary);
}

.login-input {
    background: rgba(255, 255, 255, 0.03);
