    margin-bottom: 20px;
}

.plan-free .plan-badge { background: rgba(110, 107, 133, 0.15); color: var(--text-secondary); }
.plan-pro .plan-badge { background: rgba(138, 43, 226, 0.15); color: #c084fc; }
.plan-enterprise .plan-badge { background: rgba(0, 245, 255, 0.15); color: var(--color-teal); }

